// Merge wearable sessions with member record
const member = $('Load Coaching Clients').first().json;
const activities = $input.first().json.activities || [];

const wearable_sessions_14d = activities.length;
const last_session_date = activities.length > 0 ?
  activities[0].startDate : null;

return [{
  ...member,
  wearable_sessions_14d,
  last_wearable_session: last_session_date,
  data_source: 'checkin_and_wearable'
}];

// Consent gate NOT passed — check-in data only, wearable never accessed
const member = $input.first().json;

return [{
  ...member,
  wearable_sessions_14d: null,
  last_wearable_session: null,
  data_source: 'checkin_only'
}];

// Calculate coaching risk tier per member
const members = $input.all().map(item => item.json);

function riskTier(sessions_booked, sessions_attended, days_since_checkin) {
  const attendance_rate = sessions_booked > 0 ? sessions_attended / sessions_booked : 0;
  if (attendance_rate < 0.50 || days_since_checkin > 14) return 'HIGH';
  if (attendance_rate < 0.75 || days_since_checkin > 7)  return 'MEDIUM';
  return 'LOW';
}

const scored = members.map(m => ({
  ...m,
  attendance_rate: m.sessions_booked > 0
    ? Math.round((m.sessions_attended / m.sessions_booked) * 100)
    : 0,
  risk_tier: riskTier(m.sessions_booked, m.sessions_attended, m.days_since_checkin)
}));

// Only surface HIGH and MEDIUM for briefing
const flagged = scored.filter(m => m.risk_tier !== 'LOW');

return flagged.map(m => ({ json: m }));

const member = $('Score Coaching Risk').first().json;
const llmOutput = $input.first().json;
const briefingText = llmOutput.choices?.[0]?.message?.content || 'Briefing unavailable.';

const riskLabel = member.risk_tier === 'HIGH' ? 'HIGH PRIORITY' : 'On your radar';

return [{
  json: {
    member_id: member.member_id,
    risk_tier: member.risk_tier,
    risk_label: riskLabel,
    briefing_text: briefingText,
    data_source: member.data_source,
    email_section: `<p><strong>${member.member_id}</strong> &mdash; ${riskLabel}<br>${briefingText}<br><em>Data source: ${member.data_source}</em></p>`
  }
}];

// Aggregate all coaching briefings into one email body
const items = $input.all().map(i => i.json);

const highRisk = items.filter(m => m.risk_tier === 'HIGH');
const medRisk  = items.filter(m => m.risk_tier === 'MEDIUM');

let html = `<h2>Coaching Update — ${new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long' })}</h2>`;

if (highRisk.length > 0) {
  html += `<h3>High Priority</h3>` + highRisk.map(m => m.email_section).join('');
}
if (medRisk.length > 0) {
  html += `<h3>On Your Radar</h3>` + medRisk.map(m => m.email_section).join('');
}
if (items.length === 0) {
  html += `<p>No coaching clients flagged this week. All attendance rates and check-in patterns are within normal range.</p>`;
}

html += `<hr><p style="font-size:12px;color:#888">This briefing is generated automatically from coaching session attendance and wearable data (where consented). Member names are not processed by the AI system. For questions or to update consent settings, contact your system administrator.</p>`;

return [{ json: { email_html: html, recipient_count: items.length } }];
